class Solution:
    def countNumbers(self, l: str, r: str, b: int) -> int:
        MOD = 10**9 + 7

        def count(num: str) -> int:
            n = len(num)
            res = 0
            for i in range(1, n + 1):
                res = (res + comb(i + b - 2, i - 1)) % MOD
            val = 0
            last_digit = -1
            for i, c in enumerate(num):
                digit = int(c)
                if i == 0:
                    start = 0
                else:
                    start = 0
                for j in range(start, digit):
                    if j >= last_digit:
                        res = (res + comb(n - i - 1 + b - 1 - j, n - i - 1)) % MOD
                if digit < last_digit:
                    break
                last_digit = digit
            else:
                res = (res + 1) % MOD
            return res

        def comb(n: int, k: int) -> int:
            if k > n or k < 0:
                return 0
            if k == 0 or k == n:
                return 1
            ans = 1
            for i in range(k):
                ans = ans * (n - i) % MOD
                ans = ans * pow(i + 1, -1, MOD) % MOD
            return ans

        l_val = int(l, b)
        r_val = int(r, b)
        return (count(r) - count(str(l_val - 1, b)) + MOD) % MOD
